var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"DEALER_NPC_MILITIA_NULL","text":{"KOREA":"허억......! 허억......!","JPN":"はあ、はあ……！","ENG":"*Huff... Huff...*","TWN":"呃啊……！呃啊……！"},"stage":{"bg":"CORRIDOR","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DEALER_NPC_MILITIA_NULL","text":{"KOREA":"저놈들 떨어트리는 데 왜 이렇게 오래 걸려!","JPN":"あれを落とすのになんでこんなに時間がかかるんだ！","ENG":"What took you so long to take them down?","TWN":"你怎麼這麼慢啊！"},"stage":{"bg":"CORRIDOR","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DEALER_NPC_MILITIA_NULL","text":{"KOREA":"늙은이 일부러 고생시키려고 그런 거 아냐?","JPN":"老いぼれをこき使うために、わざとやってんじゃないか？","ENG":"Were you just trying to troll me?","TWN":"是不是故意讓我吃苦啊？"},"stage":{"bg":"CORRIDOR","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"거 섭섭한 소리 하시네. 나름대로 다 합리적인 선택이라고.","JPN":"なんて悲しいことをおっしゃる。俺なりに考えて合理的な選択をしてんだ。","ENG":"Show a little gratitude, will you? There's a method behind the madness.","TWN":"說這什麼話，我明明做了最合理的選擇。"},"stage":{"bg":"CORRIDOR","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"괜히 서두르다가 괜히 오발탄이라도 날아가는 것보다는 확실하게 처리하는 게 좋잖아.","JPN":"へたに焦って外すより、確実に処理した方がいいだろ。","ENG":"It's better to be precise and accurate than to have a bullet end up in your old skull by mistake.","TWN":"太過著急會射偏的，必須沉住氣一發命中。"},"stage":{"bg":"CORRIDOR","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DEALER_NPC_MILITIA_NULL","text":{"KOREA":"끄응......","JPN":"ぐぬぬ……","ENG":"*Groan*","TWN":"呃……"},"stage":{"bg":"CORRIDOR","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DEALER_NPC_MILITIA_NULL","text":{"KOREA":"그렇게 현실적인 녀석이 왜 민병대 같은 바보짓이나 하고 있는지 모르겠군.","JPN":"そんなに現実的な奴がなぜ民兵隊のような馬鹿げたことをしているのかわからんな。","ENG":"It bewilders me that a practical lad like you is also stupid enough to stay in the Militia.","TWN":"我不明白這麼現實的人怎麼會加入民兵隊。"},"stage":{"bg":"CORRIDOR","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"그건 뭐...... 병이지. 곧 죽을 병.","JPN":"そりゃ……病気だよ。もうすぐ死んじまう病気みたいなもんさ。","ENG":"Well... I guess it must be one of those terminal diseases you can't shake off.","TWN":"那是……作孽，自作孽。"},"stage":{"bg":"CORRIDOR","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DEALER_NPC_MILITIA_NULL","text":{"KOREA":"알고 있다니 다행이군.","JPN":"それならしょうがないな。","ENG":"Well, at least you admit it.","TWN":"你明白就好。"},"stage":{"bg":"CORRIDOR","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DEALER_NPC_MILITIA_NULL","text":{"KOREA":"아 참. 이럴 때가 아니지. 지금쯤이면 데이터 분석이 끝났겠어.","JPN":"おっと、こうしてる場合じゃない。そろそろデータ分析が終わったはずだ。","ENG":"Oh, wait. Now's not the time for chitchat. The data analysis should be complete by now.","TWN":"哦，對了。資料應該分析完畢了。"},"stage":{"bg":"CORRIDOR","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DEALER_NPC_MILITIA_NULL","text":{"KOREA":"어서 확인을......","JPN":"はやく確認を……","ENG":"I'd better check—","TWN":"快去確認吧……"},"stage":{"bg":"CORRIDOR","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"......영감?","JPN":"……ジジイ？","ENG":"…You okay?","TWN":"……老頭？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"정신차려, 영감!!","JPN":"しっかりしろ、ジジイ！！","ENG":"Wake up, you old fool!","TWN":"你醒醒，老頭！！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CRIMINAL_NPC_BOSS1_NULL","text":{"KOREA":"남의 휴대폰을 주웠으면 주인에게 돌려줘야지.","JPN":"人の携帯を拾ったなら、持ち主に返すのが常識だろ。","ENG":"You really shouldn't be peeking at other people's phones like that.","TWN":"撿到手機應該還給主人才對吧。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CRIMINAL_NPC_BOSS1_NULL","text":{"KOREA":"함부로 프라이버시를 들춰보려고 하면 벌을 받는 법이야.","JPN":"勝手にプライバシーを侵害しようとしたら、罰が当たるもんだ。","ENG":"There are consequences to violating people's privacy.","TWN":"偷看別人隱私是要受到處罰的。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CRIMINAL_NPC_BOSS1_NULL","text":{"KOREA":"저렇게 머리에 총알이 박힌다거나......","JPN":"あんな風に頭に銃弾をぶち込まれても文句言えないだろう？","ENG":"For instance, you could end up with a bullet in your head, just like that...","TWN":"比如腦袋被子彈射穿……"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"이...... 개자식이......","JPN":"このクソ野郎……","ENG":"You... Son of a...","TWN":"你……狗東西……"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CRIMINAL_NPC_BOSS1_NULL","text":{"KOREA":"왜 그렇게 화를 내지?","JPN":"どうしてそんなに怒ってるんだ？","ENG":"Why are you so upset?","TWN":"你為什麼生氣？"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CRIMINAL_NPC_BOSS1_NULL","text":{"KOREA":"무기상 노인네와 그렇게 친한 관계인 줄은 몰랐는데.","JPN":"武器屋のジジイとはそんなに親しい仲だったか？","ENG":"I didn't think you were that close to the old gunsmith.","TWN":"我不知道你和武器商老頭的關係那麼親密。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"친하진 않지만...... 적어도 이런 식으로 죽을 사람은 아니었어.","JPN":"親しくはないが……少なくとも、こんな死に方をするべき人じゃなかった。","ENG":"I wasn't... but he didn't deserve to die like that.","TWN":"雖然不算親密……但他也不應該就這樣死掉。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CRIMINAL_NPC_BOSS1_NULL","text":{"KOREA":"그런가? 하지만 죽은 사람 걱정은 나중에 해도 될 것 같은데.","JPN":"そうか？　だが、死んだ人間の心配は後でいいんじゃないか？","ENG":"Is that so? But it seems he's the least of your concerns right now.","TWN":"是嗎？你還有心情同情死人呀。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CRIMINAL_NPC_BOSS1_NULL","text":{"KOREA":"지금은 자기 몸부터 걱정해야지.","JPN":"今は自分の心配をしないとな。","ENG":"You should be worried about yourself.","TWN":"先想想怎麼保住自己的性命吧。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"......이런, 젠장!","JPN":"……クソ！","ENG":"Darn it!","TWN":"……我去，該死！"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};